import type { Tests } from '@teambit/tester';
import type { CoverageResult } from '@teambit/defender.coverage-report';
import { applyThresholdsToResults } from './coverage-utils.js';

const metric = (pct: number) => ({ pct, total: 100 });
const createCoverage = (
  totalPct: number,
  filePct: number,
  filePath = 'src/index.ts'
): CoverageResult => ({
  total: {
    lines: metric(totalPct),
    functions: metric(100),
    branches: metric(100),
    statements: metric(100),
  },
  files: [
    {
      path: filePath,
      data: {
        lines: metric(filePct),
        functions: metric(100),
        branches: metric(100),
        statements: metric(100),
      },
    },
  ],
} as unknown as CoverageResult);

const createResult = (componentId: string) => ({
  components: [
    {
      componentId: { toString: () => componentId },
      results: {},
      errors: [] as Error[],
    },
  ],
}) as unknown as Tests;

describe('applyThresholdsToResults', () => {
  it('attaches coverage and leaves errors empty when thresholds are met', () => {
    const componentId = 'my-scope/my-component';
    const thresholds = { lines: 50 };
    const rootDirMap = { [componentId]: '/capsules/my-component@x.y.z' };
    const coverage = createCoverage(75, 80);
    const covByComponent = { [componentId]: coverage };

    const result = createResult(componentId);
    applyThresholdsToResults(thresholds, rootDirMap, covByComponent as any, result);

    expect((result.components[0].results as any).coverage).toBe(coverage);
    expect(result.components[0].errors).toHaveLength(0);
  });

  it('pushes an error when global thresholds are not met', () => {
    const componentId = 'my-scope/my-component';
    const thresholds = { lines: 90 };
    const rootDirMap = { [componentId]: '/capsules/my-component@x.y.z' };
    const coverage = createCoverage(80, 95);
    const covByComponent = { [componentId]: coverage };

    const result = createResult(componentId);
    applyThresholdsToResults(thresholds, rootDirMap, covByComponent as any, result as any);

    expect(result.components[0].errors).toHaveLength(1);
    expect(result.components[0].errors[0]?.message).toBe(
      'Coverage threshold not met for my-scope/my-component (lines: 80% < 90%)'
    );
  });

  it('pushes errors for files that fail pattern thresholds', () => {
    const componentId = 'my-scope/my-component';
    const thresholds = { '**/*.ts': { lines: 85 } };
    const rootDirMap = { [componentId]: '/capsules/my-component@x.y.z' };
    const coverage = createCoverage(95, 70);
    const covByComponent = { [componentId]: coverage };

    const result = createResult(componentId);
    applyThresholdsToResults(thresholds, rootDirMap, covByComponent as any, result as any);

    expect(result.components[0].errors).toHaveLength(1);
    expect(result.components[0].errors[0]?.message).toBe(
      'Coverage threshold not met for my-scope/my-component (lines: 70% < 85% in src/index.ts matching "**/*.ts")'
    );
  });

  it('pushes errors for tooltip pattern thresholds', () => {
    const componentId = 'my-scope/my-component';
    const thresholds = { '**/*my-component@*/**': { lines: 90 } };
    const rootDirMap = { [componentId]: '/capsules/my-scope_my-component@3.2.0' };
    const coverage = createCoverage(
      98,
      60,
      'sub-folder/my-file.ts'
    );
    const covByComponent = { [componentId]: coverage };

    const result = createResult(componentId);
    applyThresholdsToResults(thresholds, rootDirMap, covByComponent as any, result);

    expect(result.components[0].errors).toHaveLength(1);
    expect(result.components[0].errors[0]?.message).toBe(
      'Coverage threshold not met for my-scope/my-component (lines: 60% < 90% in sub-folder/my-file.ts matching "**/*my-component@*/**")'
    );
  });
});
